local cjson = require "cjson"
local xml = require "xml"

local function parse_xml_with_entities(xml_string)
    local entity_map = {
        ["&lt;"] = "<",
        ["&gt;"] = ">",
        ["&amp;"] = "&",
        ["&quot;"] = '"',
        ["&apos;"] = "'",
        ["&#x"] = function(code) return string.char(tonumber(code, 16)) end,
        ["&#"] = function(code) return string.char(tonumber(code)) end
    }
    
    local function decode_entities(str)
        str = str:gsub("&#x(%x+);", function(hex)
            return string.char(tonumber(hex, 16))
        end)
        str = str:gsub("&#(%d+);", function(dec)
            return string.char(tonumber(dec))
        end)
        str = str:gsub("&lt;", "<")
        str = str:gsub("&gt;", ">")
        str = str:gsub("&quot;", '"')
        str = str:gsub("&apos;", "'")
        str = str:gsub("&amp;", "&")
        return str
    end
    
    xml_string = decode_entities(xml_string)
    return xml.load(xml_string)
end

local function xml_to_table(node)
    if type(node) ~= "table" then
        return node
    end
    
    local result = {}
    
    if node[0] then
        result._tag = node[0]
    end
    
    for k, v in pairs(node) do
        if type(k) == "number" and k > 0 then
            if type(v) == "table" then
                local child = xml_to_table(v)
                local tag = v[0] or "item"
                
                if result[tag] then
                    if type(result[tag]) ~= "table" or result[tag]._tag then
                        result[tag] = {result[tag]}
                    end
                    table.insert(result[tag], child)
                else
                    result[tag] = child
                end
            else
                table.insert(result, v)
            end
        elseif type(k) == "string" and k ~= "0" then
            result[k] = v
        end
    end
    
    if #result == 1 and type(result[1]) == "string" then
        return result[1]
    end
    
    return result
end

local function extract_soap_body(parsed_xml)
    local body_content = {}
    
    local function find_body(node, path)
        if type(node) ~= "table" then
            return nil
        end
        
        local tag = node[0] or ""
        if tag:match("Body$") or tag:match(":Body$") then
            return node
        end
        
        for k, v in pairs(node) do
            if type(k) == "number" and type(v) == "table" then
                local found = find_body(v, path .. "/" .. (v[0] or ""))
                if found then
                    return found
                end
            end
        end
        
        return nil
    end
    
    local body = find_body(parsed_xml, "")
    if body then
        return xml_to_table(body)
    end
    
    return xml_to_table(parsed_xml)
end

local function parse_xml_request()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    
    if not body then
        local body_file = ngx.req.get_body_file()
        if body_file then
