local function extract_request_data(parsed_xml)
    local soap_body = extract_soap_body(parsed_xml)
    
    local data = {
        raw = soap_body,
        operation = nil,
        parameters = {}
    }
    
    if soap_body._tag then
        data.operation = soap_body._tag
    end
    
    for k, v in pairs(soap_body) do
        if k ~= "_tag" then
            data.parameters[k] = v
        end
    end
    
    if not data.operation and soap_body.Body then
        for k, v in pairs(soap_body.Body) do
            if k ~= "_tag" and type(v) == "table" then
                data.operation = k
                data.parameters = v
                break
            end
        end
    end
    
    return data
end

local function send_soap_response(data)
    ngx.header.content_type = "text/xml; charset=utf-8"
    ngx.say('<?xml version="1.0" encoding="UTF-8"?>')
    ngx.say('<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">')
    ngx.say('  <soap:Body>')
    ngx.say('    <Response>')
    ngx.say('      <status>success</status>')
    ngx.say('      <data>' .. cjson.encode(data) .. '</data>')
    ngx.say('    </Response>')
    ngx.say('  </soap:Body>')
    ngx.say('</soap:Envelope>')
end

